function solve(nums: number[]): number {
    const n = nums.length;
    if (n < 4) return 0;

    // Compute prefix sum array
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    // Compute left_incr array
    const left_incr = new Array(n).fill(1);
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            left_incr[i] = left_incr[i - 1] + 1;
        } else {
            left_incr[i] = 1;
        }
    }

    // Compute right_decr array
    const right_decr = new Array(n).fill(1);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1]) {
            right_decr[i] = right_decr[i + 1] + 1;
        } else {
            right_decr[i] = 1;
        }
    }

    // Compute right_incr array
    const right_incr = new Array(n).fill(1);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            right_incr[i] = right_incr[i + 1] + 1;
        } else {
            right_incr[i] = 1;
        }
    }

    let maxSum = -Infinity;

    for (let p = 0; p < n; p++) {
        if (left_incr[p] >= 2 && right_decr[p] >= 2) {
            const q = p + right_decr[p] - 1;
            if (right_incr[q] >= 2) {
                const l = p - left_incr[p] + 1;
                const r = q + right_incr[q] - 1;
                const currentSum = prefix[r + 1] - prefix[l];
                if (currentSum > maxSum) {
                    maxSum = currentSum;
                }
            }
        }
    }

    return maxSum;
}
